function labelOf(kind: ContributionKind, lang: Lang): string {
  return CONTRIBUTION_LABEL[kind][lang] ?? CONTRIBUTION_LABEL[kind].en;
}
function blurbOf(kind: ContributionKind, lang: Lang): string {
  return CONTRIBUTION_BLURB[kind][lang] ?? CONTRIBUTION_BLURB[kind].en;
}

/** Title + description for a contribution hub, for the route's <meta> tags. */
export function contributionMeta(
  kind: ContributionKind,
  lang: Lang,
): { title: string; description: string } {
  return { title: labelOf(kind, lang), description: blurbOf(kind, lang) };
}

/** Pages that declare a given contribution, in reading order. */
function membersOf(lang: Lang, kind: ContributionKind): ResearchDoc[] {
  return researchDocs(lang).filter((d) => d.contribution === kind);
}

function Frame({ children }: { children: React.ReactNode }) {
  return (
    <div>
      <ResearchSubnav />
      <div className="lg:grid lg:grid-cols-[15rem_minmax(0,1fr)] lg:gap-10">
        <DocsSidebar section={null} />
        <div className="min-w-0">{children}</div>
      </div>
    </div>
  );
}

function Crumbs({ current }: { current?: string }) {
  const t = useT(T);
  return (
    <nav className="flex flex-wrap items-center gap-1.5 text-sm text-muted-foreground">
      <LocalizedLink to="/research" className="hover:text-foreground">
        {t.research}
      </LocalizedLink>
      <span aria-hidden>/</span>
      <LocalizedLink to="/research/lab/experiments" className="hover:text-foreground">
        {t.experiments}
      </LocalizedLink>
      <span aria-hidden>/</span>
      {current ? (
        <>
          <LocalizedLink to={BY_CONTRIBUTION_BASE} className="hover:text-foreground">
            {t.index}
          </LocalizedLink>
          <span aria-hidden>/</span>
          <span className="text-foreground">{current}</span>
        </>
      ) : (
        <span className="text-foreground">{t.index}</span>
      )}
    </nav>
  );
}

function PageCard({ doc }: { doc: ResearchDoc }) {
  const { lang } = useLang();
  return (
    <LocalizedLink
      to={doc.url}
      className="group block rounded-lg border p-4 transition-shadow hover:shadow-md"
    >
      <div className="flex items-center gap-2">
        <span className={cn("h-2 w-2 shrink-0 rounded-full", KIND_DOT[doc.kind])} aria-hidden />
        <span className="text-[10px] font-medium uppercase tracking-wide text-muted-foreground">
          {kindLabel(doc.kind, lang)}
        </span>
      </div>
      <div className="mt-1.5 text-sm font-semibold tracking-tight group-hover:underline">
        {doc.title}
      </div>
      <p className="mt-1 text-xs leading-snug text-muted-foreground">{doc.description}</p>
    </LocalizedLink>
  );
}

export function ContributionIndex() {
  const t = useT(T);
  const { lang } = useLang();
  const counts = new Map<ContributionKind, number>();
  for (const k of CONTRIBUTION_ORDER) counts.set(k, membersOf(lang, k).length);
  const present = CONTRIBUTION_ORDER.filter((k) => (counts.get(k) ?? 0) > 0);
  const negativeCount = counts.get("negative") ?? 0;

  return (
    <Frame>
      <Crumbs />
      <header className="mt-4 space-y-3">
        <h1 className="text-3xl font-bold tracking-tight sm:text-4xl">{t.index}</h1>
        <p className="text-lg text-muted-foreground">{t.indexLede}</p>
      </header>

      {negativeCount > 0 && (
        <LocalizedLink
          to={`${BY_CONTRIBUTION_BASE}/negative`}
          className="group mt-6 block rounded-lg border border-rose-500/30 bg-rose-500/5 p-4 transition-shadow hover:shadow-md"
        >
          <div className="flex items-baseline justify-between gap-2">
            <span className="text-sm font-semibold tracking-tight text-rose-700 group-hover:underline dark:text-rose-300">
              {t.negativeCallout}
            </span>
            <span className="text-xs tabular-nums text-muted-foreground">
              {t.pages(negativeCount)}
            </span>
          </div>
          <p className="mt-1.5 text-xs leading-relaxed text-muted-foreground">
            {t.negativeCalloutBody}
          </p>
        </LocalizedLink>
      )}

      <div className="mt-8 grid gap-3 sm:grid-cols-2">
        {present.map((k) => (
          <LocalizedLink
            key={k}
            to={`${BY_CONTRIBUTION_BASE}/${k}`}
            className="group block rounded-lg border p-4 transition-shadow hover:shadow-md"
          >
            <div className="flex items-baseline justify-between gap-2">
              <span className="text-sm font-semibold tracking-tight group-hover:underline">
                {labelOf(k, lang)}
              </span>
              <span className="text-xs tabular-nums text-muted-foreground">
                {t.pages(counts.get(k) ?? 0)}
              </span>
            </div>
            <p className="mt-1.5 text-xs leading-relaxed text-muted-foreground">{blurbOf(k, lang)}</p>
          </LocalizedLink>
        ))}
      </div>
    </Frame>
  );
}

export function ContributionHub({ kind }: { kind: ContributionKind }) {
  const t = useT(T);
  const { lang } = useLang();
  const members = membersOf(lang, kind);
  return (
    <Frame>
      <Crumbs current={labelOf(kind, lang)} />
      <header className="mt-4 space-y-3">
        <h1 className="text-3xl font-bold tracking-tight sm:text-4xl">{labelOf(kind, lang)}</h1>
        <p className="text-lg text-muted-foreground">{blurbOf(kind, lang)}</p>
      </header>
      {members.length === 0 ? (
        <p className="mt-8 rounded-lg border border-dashed p-6 text-sm text-muted-foreground">
          {t.empty}
        </p>
      ) : (
        <>
          <p className="mt-6 text-sm text-muted-foreground">{t.pages(members.length)}</p>
          <div className="mt-3 grid gap-3 sm:grid-cols-2">
            {members.map((d) => (
              <PageCard key={d.url} doc={d} />
            ))}
          </div>
        </>
      )}
    </Frame>
  );
}

/** by-contribution index URL, or a hub's ContributionKind, or null if not one
 *  of these routes. Returns "" for the index. */
export function contributionRouteFor(path: string): "" | ContributionKind | null {
  if (path === BY_CONTRIBUTION_BASE) return "";
  const m = new RegExp(`^${BY_CONTRIBUTION_BASE}/([a-z-]+)$`).exec(path);
  const slug = m?.[1];
  if (!slug) return null;
  return (CONTRIBUTION_ORDER as readonly string[]).includes(slug)
    ? (slug as ContributionKind)
    : null;
}
